export const BEHAVIOR_CATEGORY_PACKS = BEHAVIOR_CATEGORY_CATALOG.map((category) => ({
  id: category.id,
  label: category.label,
  description: String(category.items.length) + " behaviors",
  behaviorIds: category.items.map((item) => item.id),
}));

export const BEHAVIOR_SUBCATEGORY_OPTIONS = BEHAVIOR_CATEGORY_CATALOG.flatMap((category) =>
  category.items.map((item) => ({
    ...item,
    categoryId: category.id,
    categoryLabel: category.label,
  })),
);

export const BEHAVIOR_SUBCATEGORY_BY_ID = new Map(
  BEHAVIOR_SUBCATEGORY_OPTIONS.map((item) => [item.id, item]),
);

export const BEHAVIOR_CATEGORY_BY_ID = new Map(
  BEHAVIOR_CATEGORY_CATALOG.map((category) => [category.id, category]),
);
